 24→export function setupSmokeSuite(suiteName: string): () => SmokeTestRuntime {
 25→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 26→  const namespace = `smoke_${runId}`;
 27→  const suiteSlug = suiteName
 28→    .toLowerCase()
