128→    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
129→      try {
130→        await withTimeout(() => runtime!.surreal.query(`REMOVE DATABASE ${database};`), 10_000, "remove test database");
131→      } catch {
