153→export type TestUser = {
154→  headers: Record<string, string>;
155→};
156→
157→export async function createTestUser(baseUrl: string, suffix: string): Promise<TestUser> {
158→  const email = `smoke-${Date.now()}-${suffix}@test.local`;
159→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
160→    method: "POST",
161→    headers: { "Content-Type": "application/json" },
162→    body: JSON.stringify({ name: "Smoke Tester", email, password: "smoke-test-password-123" }),
163→    redirect: "manual",
164→  });
165→
166→  if (!response.ok) {
167→    const body = await response.text();
168→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
169→  }
170→
171→  const setCookie = response.headers.getSetCookie();
172→  if (!setCookie || setCookie.length === 0) {
173→    throw new Error("Sign-up did not return session cookies");
174→  }
175→
176→  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
177→  return { headers: { Cookie: cookieHeader } };
178→}
179→
180→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
181→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
182→  if (!response.ok || !response.body) {
183→    throw new Error(`Failed to open SSE stream (${response.status})`);
184→  }
185→
186→  const reader = response.body.getReader();
187→  const decoder = new TextDecoder();
188→  const events: T[] = [];
189→  let buffer = "";
190→
191→  const timeout = setTimeout(() => {
192→    void reader.cancel();
193→  }, timeoutMs);
194→
195→  try {
196→    while (true) {
197→      const { value, done } = await reader.read();
198→      if (done) {
199→        break;
200→      }
201→
202→      buffer += decoder.decode(value, { stream: true });
203→      const segments = buffer.split("\n\n");
204→      buffer = segments.pop() ?? "";
205→
206→      for (const segment of segments) {
207→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
208→        if (!dataLine) {
209→          continue;
210→        }
211→
212→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
213→        events.push(event);
214→
215→        if (event.type === "error") {
216→          const errorText = (event as { error?: string }).error;
217→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
218→        }
219→
220→        if (event.type === "done") {
221→          return events;
222→        }
223→      }
224→    }
225→  } finally {
226→    clearTimeout(timeout);
227→    reader.releaseLock();
228→  }
229→
230→  return events;
231→}
232→
233→export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
234→  const response = await fetch(url, init);
235→  if (!response.ok) {
236→    const body = await response.text();
237→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
238→  }
239→
240→  return (await response.json()) as T;
241→}
242→
243→function base64url(buf: Buffer): string {
244→  return buf.toString("base64url");
245→}
246→
247→function generatePkce(): { verifier: string; challenge: string } {
248→  const verifier = base64url(randomBytes(32));
249→  const challenge = base64url(createHash("sha256").update(verifier).digest());
250→  return { verifier, challenge };
251→}
252→
253→/**
254→ * Obtain an OAuth2 JWT access token for MCP endpoints.
255→ * Requires a SurrealDB connection to skip consent screen.
256→ */
257→export async function getOAuthToken(
258→  baseUrl: string,
259→  surreal: Surreal,
260→  sessionHeaders: Record<string, string>,
261→  scopes: string = "graph:read graph:reason session:write offline_access",
262→): Promise<string> {
263→  // Trigger JWKS key generation if not yet done
264→  await fetch(`${baseUrl}/api/auth/jwks`);
265→
266→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
267→    method: "POST",
268→    headers: { "Content-Type": "application/json" },
269→    body: JSON.stringify({
270→      client_name: `smoke-test-${Date.now()}`,
271→      redirect_uris: ["http://127.0.0.1:9999/callback"],
272→      grant_types: ["authorization_code", "refresh_token"],
273→      response_types: ["code"],
274→      token_endpoint_auth_method: "none",
275→    }),
276→  });
277→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
278→
279→  const { client_id } = (await dcrRes.json()) as { client_id: string };
280→
281→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
282→    cid: client_id,
283→  });
284→
285→  const { verifier, challenge } = generatePkce();
286→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
287→  authUrl.searchParams.set("client_id", client_id);
288→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
289→  authUrl.searchParams.set("response_type", "code");
290→  authUrl.searchParams.set("scope", scopes);
291→  authUrl.searchParams.set("state", "test-state");
292→  authUrl.searchParams.set("code_challenge", challenge);
293→  authUrl.searchParams.set("code_challenge_method", "S256");
294→  authUrl.searchParams.set("resource", baseUrl);
295→
296→  const authRes = await fetch(authUrl.toString(), {
297→    headers: sessionHeaders,
298→    redirect: "manual",
299→  });
300→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
301→
302→  const location = authRes.headers.get("location")!;
303→  const redirectUrl = new URL(location, baseUrl);
304→  const code = redirectUrl.searchParams.get("code") ?? "";
305→  if (!code) throw new Error(`No code in redirect: ${location}`);
306→
307→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
308→    method: "POST",
309→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
310→    body: new URLSearchParams({
311→      grant_type: "authorization_code",
312→      code,
313→      redirect_uri: "http://127.0.0.1:9999/callback",
314→      client_id,
315→      code_verifier: verifier,
316→      resource: baseUrl,
317→    }),
318→  });
319→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
320→
321→  const tokens = (await tokenRes.json()) as { access_token: string };
322→  return tokens.access_token;
323→}
324→
325→export type TestUserWithMcp = TestUser & {
326→  mcpHeaders: Record<string, string>;
327→};
328→
329→/**
330→ * Create a test user with both session cookie and OAuth MCP token.
331→ */
332→export async function createTestUserWithMcp(
333→  baseUrl: string,
334→  surreal: Surreal,
335→  suffix: string,
336→  scopes?: string,
337→): Promise<TestUserWithMcp> {
338→  const user = await createTestUser(baseUrl, suffix);
339→  const accessToken = await getOAuthToken(baseUrl, surreal, user.headers, scopes);
340→  return {
341→    ...user,
342→    mcpHeaders: { Authorization: `Bearer ${accessToken}` },
343→  };
344→}
345→
346→function requireTestEnv(name: string): string {
347→  const value = process.env[name];
348→  if (!value || value.trim().length === 0) {
349→    throw new Error(`Smoke test requires env var ${name}`);
350→  }
351→  return value;
352→}
353→
354→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
355→  return await Promise.race([
356→    callback(),
357→    new Promise<T>((_, reject) => {
358→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
359→    }),
360→  ]);
361→}
