 38→async function pollForTaskStatus(
 39→  surreal: ReturnType<typeof setupSmokeSuite> extends () => infer R ? (R extends { surreal: infer S } ? S : never) : never,
 40→  taskRecord: RecordId<"task", string>,
 41→  expectedStatus: string,
 42→  timeoutMs: number,
 43→): Promise<string | undefined> {
 44→  const start = Date.now();
 45→  while (Date.now() - start < timeoutMs) {
 46→    const [rows] = await surreal
 47→      .query<[Array<{ status: string }>]>(
 48→        "SELECT status FROM $task;",
 49→        { task: taskRecord },
 50→      )
 51→      .collect<[Array<{ status: string }>]>();
 52→    if (rows[0]?.status === expectedStatus) return rows[0].status;
 53→    await Bun.sleep(500);
 54→  }
 55→  // Return whatever status it has now
 56→  const [rows] = await surreal
 57→    .query<[Array<{ status: string }>]>(
 58→      "SELECT status FROM $task;",
 59→      { task: taskRecord },
 60→    )
 61→    .collect<[Array<{ status: string }>]>();
