 17→
 18→export async function processGitCommits(input: ProcessWebhookInput): Promise<ProcessWebhookResult> {
 19→  const startedAt = performance.now();
 20→  const workspaceId = input.workspaceRecord.id as string;
 21→
 22→  logInfo("webhook.commits.started", "Processing commits", {
 23→    workspaceId,
 24→    repository: input.event.repository.full_name,
 25→    commitCount: input.event.commits.length,
 26→  });
 27→
 28→  const projects = await loadWorkspaceProjects(input.surreal, input.workspaceRecord);
 29→  const projectNames = projects.map((p) => p.name);
 30→
 31→  const [workspaceRows] = await input.surreal
 32→    .query<[Array<{ name: string }>]>("SELECT name FROM $workspace LIMIT 1;", {
 33→      workspace: input.workspaceRecord,
 34→    })
 35→    .collect<[Array<{ name: string }>]>();
 36→  const workspaceName = workspaceRows[0]?.name;
 37→
 38→  const isDefaultBranch = input.event.ref === `refs/heads/${input.event.repository.default_branch}`;
 39→
 40→  const result: ProcessWebhookResult = {
 41→    commitsProcessed: 0,
 42→    commitsSkipped: 0,
 43→    totalEntities: 0,
 44→    totalRelationships: 0,
 45→    autoLinkedDecisions: [],
 46→    observationsCreated: [],
 47→    taskStatusUpdates: [],
 48→  };
 49→
 50→  for (const rawCommit of input.event.commits) {
 51→    const commit: CommitInput = {
 52→      sha: rawCommit.id,
 53→      message: rawCommit.message,
 54→      authoredAt: rawCommit.timestamp,
 55→      authorName: rawCommit.author.name,
 56→      authorEmail: rawCommit.author.email,
 57→      authorUsername: rawCommit.author.username,
 58→      url: rawCommit.url,
 59→      repository: input.event.repository.full_name,
 60→    };
 61→
 62→    try {
 63→      const commitResult = await processCommit({
 64→        surreal: input.surreal,
 65→        extractionModel: input.extractionModel,
 66→        embeddingModel: input.embeddingModel,
 67→        embeddingDimension: input.embeddingDimension,
 68→        extractionStoreThreshold: input.extractionStoreThreshold,
 69→        extractionModelId: input.extractionModelId,
 70→        workspaceRecord: input.workspaceRecord,
 71→        commit,
 72→        workspaceName,
 73→        projectNames,
 74→        autoLinkThreshold: input.autoLinkThreshold,
 75→        isDefaultBranch,
 76→        now: new Date(),
 77→      });
 78→
 79→      result.commitsProcessed += 1;
 80→      result.totalEntities += commitResult.entities.length;
 81→      result.totalRelationships += commitResult.relationships.length;
 82→      result.autoLinkedDecisions.push(...commitResult.autoLinkedDecisions);
 83→      result.observationsCreated.push(...commitResult.observationsCreated);
 84→      result.taskStatusUpdates.push(...commitResult.taskStatusUpdates);
 85→    } catch (error) {
 86→      logError("webhook.commit.failed", "Failed to process commit", error, {
 87→        workspaceId,
 88→        sha: commit.sha,
 89→      });
 90→      result.commitsSkipped += 1;
 91→    }
 92→  }
 93→
 94→  logInfo("webhook.commits.completed", "Finished processing commits", {
 95→    workspaceId,
 96→    ...result,
 97→    durationMs: elapsedMs(startedAt),
 98→  });
 99→
100→  return result;
101→}
102→
103→async function processCommit(input: {
104→  surreal: typeof import("surrealdb").Surreal.prototype;
105→  extractionModel: unknown;
106→  embeddingModel: unknown;
107→  embeddingDimension: number;
108→  extractionStoreThreshold: number;
109→  extractionModelId: string;
