 12→export type SmokeTestRuntime = {
 13→  baseUrl: string;
 14→  surreal: Surreal;
 15→  namespace: string;
 16→  database: string;
 17→  port: number;
 18→};
 19→
 20→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
