 24→export function setupSmokeSuite(suiteName: string): () => SmokeTestRuntime {
 25→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 26→  const namespace = `smoke_${runId}`;
 27→  const suiteSlug = suiteName
 28→    .toLowerCase()
 29→    .replace(/[^a-z0-9]+/g, "_")
 30→    .replace(/^_+|_+$/g, "");
 31→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
 32→
 33→  let runtime: SmokeTestRuntime | undefined;
 34→  let server: ReturnType<typeof Bun.serve> | undefined;
 35→  let runtimeSurreal: Surreal | undefined;
 36→  let analyticsSurreal: Surreal | undefined;
 37→  let setupSucceeded = false;
 38→
 39→  beforeAll(async () => {
 40→    const surreal = new Surreal();
 41→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
 42→    await withTimeout(
 43→      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
 44→      10_000,
 45→      "authenticate with SurrealDB",
 46→    );
 47→
 48→    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
 49→    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
 50→    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
 51→    await withTimeout(
 52→      () => surreal.use({ namespace, database }),
 53→      10_000,
 54→      "switch to test namespace/database",
 55→    );
 56→
 57→    const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
 58→    await withTimeout(() => surreal.query(schemaSql), 20_000, "apply schema");
 59→
 60→    // Reserve a port so betterAuth gets the real URL at init time
 61→    const tempServer = Bun.serve({ port: 0, fetch: () => new Response() });
 62→    const reservedPort = tempServer.port;
 63→    tempServer.stop(true);
 64→    const baseUrl = `http://127.0.0.1:${reservedPort}`;
 65→
 66→    const config: ServerConfig = {
 67→      openRouterApiKey: requireTestEnv("OPENROUTER_API_KEY"),
 68→      chatAgentModelId: requireTestEnv("CHAT_AGENT_MODEL"),
 69→      extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
 70→      pmAgentModelId: process.env.PM_AGENT_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
 71→      analyticsAgentModelId: requireTestEnv("ANALYTICS_MODEL"),
 72→      embeddingModelId: requireTestEnv("OPENROUTER_EMBEDDING_MODEL"),
 73→      embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
 74→      extractionStoreThreshold: Number(requireTestEnv("EXTRACTION_STORE_THRESHOLD")),
 75→      extractionDisplayThreshold: Number(requireTestEnv("EXTRACTION_DISPLAY_THRESHOLD")),
 76→      surrealUrl,
 77→      surrealUsername,
 78→      surrealPassword,
 79→      surrealNamespace: namespace,
 80→      surrealDatabase: database,
 81→      port: reservedPort,
 82→      betterAuthSecret: process.env.BETTER_AUTH_SECRET ?? "smoke-test-secret-at-least-32-chars-long",
 83→      betterAuthUrl: baseUrl,
 84→      githubClientId: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
 85→      githubClientSecret: process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
 86→    };
 87→
 88→    const deps = await createRuntimeDependencies(config);
 89→    runtimeSurreal = deps.surreal;
 90→    analyticsSurreal = deps.analyticsSurreal;
 91→
 92→    const serverDeps: ServerDependencies = {
 93→      config,
 94→      surreal: deps.surreal,
 95→      analyticsSurreal: deps.analyticsSurreal,
 96→      auth: deps.auth,
 97→      chatAgentModel: deps.chatAgentModel,
 98→      extractionModel: deps.extractionModel,
 99→      pmAgentModel: deps.pmAgentModel,
100→      analyticsAgentModel: deps.analyticsAgentModel,
101→      embeddingModel: deps.embeddingModel,
102→      sse: createSseRegistry(),
103→    };
104→
105→    server = createBrainServer(serverDeps);
106→    const port = server.port;
107→
108→    runtime = { baseUrl, surreal, namespace, database, port };
109→    setupSucceeded = true;
110→  }, 60_000);
111→
112→  afterAll(async () => {
113→    if (server) {
114→      server.stop(true);
115→    }
116→
117→    if (runtimeSurreal) {
118→      await runtimeSurreal.close().catch(() => undefined);
119→    }
120→    if (analyticsSurreal) {
121→      await analyticsSurreal.close().catch(() => undefined);
122→    }
123→
124→    if (!runtime) {
125→      return;
126→    }
127→
128→    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
129→      try {
130→        await withTimeout(() => runtime!.surreal.query(`REMOVE DATABASE ${database};`), 10_000, "remove test database");
131→      } catch {
132→        // Best effort cleanup.
133→      }
134→
135→      try {
136→        await withTimeout(() => runtime!.surreal.query(`REMOVE NAMESPACE ${namespace};`), 10_000, "remove test namespace");
137→      } catch {
138→        // Best effort cleanup.
139→      }
140→    }
141→
142→    await withTimeout(() => runtime!.surreal.close(), 2_000, "close SurrealDB").catch(() => undefined);
143→  }, 20_000);
144→
145→  return () => {
146→    if (!runtime) {
147→      throw new Error("Smoke runtime requested before suite setup completed");
148→    }
149→    return runtime;
150→  };
151→}
