162→    body: JSON.stringify({ name: "Smoke Tester", email, password: "smoke-test-password-123" }),
163→    redirect: "manual",
164→  });
165→
166→  if (!response.ok) {
167→    const body = await response.text();
168→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
169→  }
170→
171→  const setCookie = response.headers.getSetCookie();
172→  if (!setCookie || setCookie.length === 0) {
173→    throw new Error("Sign-up did not return session cookies");
