243→function base64url(buf: Buffer): string {
244→  return buf.toString("base64url");
245→}
246→
247→function generatePkce(): { verifier: string; challenge: string } {
248→  const verifier = base64url(randomBytes(32));
249→  const challenge = base64url(createHash("sha256").update(verifier).digest());
250→  return { verifier, challenge };
251→}
