213→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
214→  const result: Record<string, unknown> = {};
215→  for (const [key, value] of Object.entries(obj)) {
216→    if (value !== undefined) {
217→      result[key] = value;
218→    }
219→  }
220→  return result as Partial<T>;
221→}
