267→async function lookupSession(
268→  surreal: Surreal,
269→  sessionId: string,
270→): Promise<SessionLookup> {
271→  const record = new RecordId("agent_session", sessionId);
272→  const session = await surreal.select<SessionRow>(record);
273→  if (!session) {
274→    return { ok: false, error: sessionNotFound(sessionId) };
275→  }
276→  if (!session.orchestrator_status) {
277→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
278→  }
279→  const status = session.orchestrator_status as OrchestratorStatus;
280→  return { ok: true, session, record, status };
281→}
