322→    workspaceRecord: RecordId<"workspace", string>;
323→    taskId?: string;
324→  }) => Promise<{ session_id: string }>;
325→};
326→
327→export async function createOrchestratorSession(
328→  input: CreateSessionInput,
329→): Promise<OrchestratorSessionResult> {
330→  // 1. Validate assignment eligibility
331→  const assignmentResult = await input.validateAssignment(
332→    input.surreal,
333→    input.workspaceId,
334→    input.taskId,
335→  );
336→
337→  if (!assignmentResult.ok) {
338→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
339→  }
340→
341→  const { validation } = assignmentResult;
342→  const taskSlug = `${slugFromTitle(validation.title)}-${Date.now()}`;
343→  const repoRoot = validation.repoPath;
344→
345→  // 2. Create worktree
346→  const worktreeResult = await createWorktree(
347→    input.shellExec,
348→    repoRoot,
349→    taskSlug,
350→  );
351→
352→  if (!worktreeResult.ok) {
353→    return {
354→      ok: false,
355→      error: worktreeError(worktreeResult.error.message),
356→    };
357→  }
358→
359→  const { branchName, worktreePath } = worktreeResult.value;
360→
361→  // 3. Create agent_session record
362→  const { session_id: agentSessionId } = await input.createAgentSession({
363→    surreal: input.surreal,
364→    agent: "claude-agent-sdk",
365→    workspaceRecord: validation.workspaceRecord,
366→    taskId: input.taskId,
367→  });
368→
369→  const streamId = generateStreamId(agentSessionId);
370→
371→  // 4. Build config and spawn agent
372→  const agentSpawnConfig: AgentSpawnConfig = {
373→    prompt: `/brain-start-task ${input.taskId}`,
374→    workDir: worktreePath,
375→    workspaceId: input.workspaceId,
376→    brainBaseUrl: input.brainBaseUrl,
377→  };
378→
379→  const spawnFn = input.spawnAgent ?? defaultSpawnAgent;
380→  let handle: AgentHandle;
381→  try {
382→    handle = spawnFn(agentSpawnConfig);
383→  } catch (err) {
384→    // Rollback: remove worktree and delete agent_session on spawn failure
385→    await removeWorktree(input.shellExec, repoRoot, branchName);
386→    const sessionRecord = new RecordId("agent_session", agentSessionId);
387→    await input.surreal.delete(sessionRecord);
388→    return {
389→      ok: false,
390→      error: worktreeError(`Failed to spawn agent: ${err instanceof Error ? err.message : String(err)}`),
391→    };
392→  }
393→
394→  // 5. Register handle for later abort
395→  handleRegistry.set(agentSessionId, handle);
396→
397→  // 6. Update agent_session with orchestrator fields
398→  const sessionRecord = new RecordId("agent_session", agentSessionId);
399→  await input.surreal.update(sessionRecord).merge({
400→    orchestrator_status: "spawning" as OrchestratorStatus,
401→    worktree_branch: branchName,
402→    worktree_path: worktreePath,
403→    stream_id: streamId,
404→  });
405→
406→  return {
407→    ok: true,
408→    value: {
409→      agentSessionId,
410→      streamId,
411→      worktreeBranch: branchName,
412→    },
413→  };
414→}
