475→export async function abortOrchestratorSession(
476→  input: AbortSessionInput,
477→): Promise<AbortSessionResult> {
478→  const lookup = await lookupSession(input.surreal, input.sessionId);
479→  if (!lookup.ok) {
480→    return { ok: false, error: lookup.error };
481→  }
482→  const { session, record: sessionRecord } = lookup;
483→
484→  // 1. Abort the agent process if handle exists
485→  const handle = handleRegistry.get(input.sessionId);
486→  if (handle) {
