501→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
502→  }
503→
504→  // 4. Return task to ready
505→  if (session.task_id) {
506→    await input.surreal.update(session.task_id).merge({
507→      status: "ready",
508→      updated_at: new Date(),
509→    });
510→  }
511→
512→  // 5. End the agent session
513→  await input.endAgentSession({
514→    surreal: input.surreal,
515→    workspaceRecord,
516→    sessionId: input.sessionId,
517→    summary: "Session aborted",
518→  });
