646→    ? diffResult.value
647→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
648→
649→  // Get task title
650→  const taskId = session.task_id ? session.task_id.id : "";
651→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
652→
653→  return {
654→    ok: true,
655→    value: {
656→      taskTitle,
657→      diff,
658→      session: {
659→        orchestratorStatus: status,
660→        ...pickDefined({
661→          worktreeBranch: session.worktree_branch,
662→          startedAt: session.started_at,
663→          lastEventAt: session.last_event_at,
