 18→export async function processGitCommits(input: ProcessWebhookInput): Promise<ProcessWebhookResult> {
 19→  const startedAt = performance.now();
 20→  const workspaceId = input.workspaceRecord.id as string;
 21→
 22→  logInfo("webhook.commits.started", "Processing commits", {
 23→    workspaceId,
